# ==========================================================
# Wireless Downlink Optimization under Sparse Jamming Attacks
# Windows Local Version
# Modified to load data from .mat files generated by data-wireless-mat.jl
# ==========================================================

using JuMP, MosekTools, CSV, DataFrames, Distributions, LinearAlgebra, Printf, Random
using PrettyTables, Combinatorics, Statistics
using MAT  # Added for loading .mat files

# --- 1. Load Data from .mat File ---
function load_wireless_data(n_BS, n_J, m_UE; seed=42, mat_dir="instances")
    fname = joinpath(mat_dir, "RJ_$(n_BS)BS_$(n_J)J_$(m_UE)UE_seed$(seed).mat")
    if !isfile(fname)
        error("MAT file not found: $fname. Please generate it using data-wireless-mat.jl.")
    end
    data = matread(fname)
    
    h =  data["gains_h"]  # m_UE x n_BS
    g_mat =  data["gains_g"]  # m_UE x n_BS x n_J
    g = permutedims(g_mat, [1, 3, 2])  # Permute to m_UE x n_J x n_BS to match algorithm's g[k, j, i]
    
    p_bar = ones(n_BS) * data["p_max"] #* 1.5  # Increase by 50% # Use p_max from .mat (e.g., 40.0)
    gamma = fill(data["gamma"], m_UE)  # Vector of gamma values
    sigma2 = data["noise"]  # Noise vector from .mat
    # 🔑 CRITICAL: Load U_max and u_max from .mat (no hardcoding!)
    U_max = data["Umax"]
    u_max = data["umax"]
    return h, g, p_bar, gamma, sigma2, U_max, u_max
end

# --- 2. Sparse Projection onto {0 ≤ u ≤ 1, ‖u‖₀ ≤ s} ---
function sparse_project(u_tilde, s)
    n = length(u_tilde)
    idx = sortperm(abs.(u_tilde), rev=true)[1:s]
    u_proj = zeros(n)
    for i in idx
        u_proj[i] = max(u_tilde[i], 0)  # Ensure non-negativity
    end
    return u_proj
end

# --- 3. Worst-Case Subproblem for User k ---
function worst_case_jammer(c_k, s; method="heuristic", optimizer=Mosek.Optimizer, total_time=0.0,
                           U_max=1000.0,   # ← added
                           u_max=800.0)    # ← added
    n_J = length(c_k)
    #Umax=1000
    #umax=800
    model = Model(optimizer)
    set_silent(model)
    remaining_time = max(0.0, 1000.0 - total_time)
    set_optimizer_attribute(model, "MSK_DPAR_OPTIMIZER_MAX_TIME", remaining_time)

    if method == "heuristic"
        @variable(model, 0 <= u[1:n_J]<=u_max)
        @constraint(model, sum(u[j]^2 for j in 1:n_J) <= U_max^2)
        @objective(model, Max, sum(c_k[j] * u[j] for j in 1:n_J))
        optimize!(model)
        if termination_status(model) != MOI.OPTIMAL
            @warn "Heuristic subproblem not optimal: $(termination_status(model)), time used: $(solve_time(model))s"
            return zeros(n_J)
        end
        u = value.(u)
        return sparse_project(u, s)
    elseif method == "mip"
        @variable(model, 0 <= u[1:n_J] <=u_max)
        @variable(model, z[1:n_J], Bin)
        @constraint(model, u .<= u_max*z)
        @constraint(model, sum(z) <= s)
        @constraint(model, sum(u[j]^2 for j in 1:n_J) <= U_max^2)
        @objective(model, Max, sum(c_k[j] * u[j] for j in 1:n_J))
        optimize!(model)
        if termination_status(model) != MOI.OPTIMAL
            @warn "MIP subproblem not optimal: $(termination_status(model)), time used: $(solve_time(model))s"
            return zeros(n_J)
        end
        return value.(u)
    elseif method == "relaxed"
        @variable(model, 0 <= u[1:n_J]<=u_max)
        @variable(model, 0 <= z[1:n_J] <= 1)
        @constraint(model, u .<= u_max*z)
        @constraint(model, sum(z) <= s)
        @constraint(model, sum(u[j]^2 for j in 1:n_J) <= U_max^2)
        @objective(model, Max, sum(c_k[j] * u[j] for j in 1:n_J))
        optimize!(model)
        if termination_status(model) != MOI.OPTIMAL
            @warn "Relaxed subproblem not optimal: $(termination_status(model)), time used: $(solve_time(model))s"
            return zeros(n_J)
        end
        u_val = value.(u)
        return sparse_project(u_val, s)
    else
        error("Unknown method: $method. Use 'heuristic', 'mip', 'relaxed', or 'analytical'.")
    end
end

# --- 4. Solve Master Problem (RO-RJ with finite scenarios) ---
function solve_master_wireless(h, g, p_bar, gamma, sigma2, scenarios; optimizer=Mosek.Optimizer, total_time=0.0)
    m_UE, n_J, n_BS = size(g)
    model = Model(optimizer)
    set_silent(model)
    remaining_time = max(0.0, 1000.0 - total_time)
    set_optimizer_attribute(model, "MSK_DPAR_OPTIMIZER_MAX_TIME", remaining_time)
    @variable(model, 0 <= p[i=1:n_BS] <= p_bar[i])
    @objective(model, Min, sum(p))
    for k in 1:m_UE
        for u in scenarios
            interference_from_jammer = sum(u[j] * sum(p[i] * g[k, j, i] for i in 1:n_BS) for j in 1:n_J)
            sinr_term = sum(p[i] * h[k, i] for i in 1:n_BS) - gamma[k] * sigma2[k] - gamma[k] * interference_from_jammer
            #sinr_term = sum(p[i] * h[k, i] for i in 1:n_BS) - gamma * sigma2 - gamma * interference_from_jammer
            @constraint(model, sinr_term >= 0)
        end
    end
    optimize!(model)
    if termination_status(model) != MOI.OPTIMAL
        @warn "Master problem not optimal: $(termination_status(model)), time used: $(solve_time(model))s"
        return zeros(n_BS), Inf
    end
    return value.(p), objective_value(model)
end

# --- 5. Solve Nominal Problem (u = 0, i.e., no jamming) ---
function solve_nominal_wireless(h, p_bar, gamma, sigma2; optimizer=Mosek.Optimizer)
    m_UE, n_BS = size(h)
    model = Model(optimizer)
    set_silent(model)
    @variable(model, 0 <= p[i=1:n_BS] <= p_bar[i])
    @objective(model, Min, sum(p))
    for k in 1:m_UE
        @constraint(model, sum(p[i] * h[k, i] for i in 1:n_BS) - gamma[k] * sigma2[k] >= 0)
    end
    optimize!(model)
    if termination_status(model) != MOI.OPTIMAL
        @warn "Nominal wireless problem not optimal."
        return zeros(n_BS)
    end
    return value.(p)
end

# =============================================================================
# 6. Cutting Plane Algorithm for Wireless Optimization
# =============================================================================
function cutting_plane_wireless(
    h, g, p_bar, gamma, sigma2, s;
    method="heuristic",
    max_iter=5000,
    tol=1e-5,
    limit_time=1000.0,
    verbose=true,
    optimizer=Mosek.Optimizer,
    p_init=nothing,
    seed::Int=23,
    m_UE::Int=size(g, 1),
    n_J::Int=size(g, 2),
     n_BS::Int=size(g, 3),
    U_max::Float64=1000.0,      # ← added
    u_max::Float64=800.0        # ← added
)

    # Containers for scenario sets and τ history
    S = Vector{Vector{Float64}}()
    tau_history = Vector{Tuple{Int, Float64}}()

    # -------------------------------------------------------------------------
    # Initialization
    # -------------------------------------------------------------------------
    if isnothing(p_init)
        error("Initial power vector 'p_init' must be provided for wireless cutting-plane algorithm.")
    else
        p_current = p_init
        total_algorithm_time = 0.0
        if verbose
            println("(Initialized from provided solution (Seed $seed | m_UE=$m_UE, n_J=$n_J, n_BS=$n_BS | $method).)")
        end
    end

    τ_prev = Inf

    # -------------------------------------------------------------------------
    # Main Cutting-Plane Iteration Loop
    # -------------------------------------------------------------------------
    for ℓ in 1:max_iter
        if total_algorithm_time > limit_time
            if verbose
                println("⏰ Time limit ($limit_time s) exceeded at iteration $ℓ ($method | Seed $seed | m_UE=$m_UE, n_J=$n_J, n_BS=$n_BS)")
            end
            break
        end

        iter_time = 0.0
        new_scenarios = Vector{Vector{Float64}}()

        # ---------------------------------------------------------------------
        # Subproblem: Find worst-case jammer for each user
        # ---------------------------------------------------------------------
        t_sub = @elapsed begin
            for k in 1:m_UE
                c_k = [sum(p_current[i] * g[k, j, i] for i in 1:n_BS) for j in 1:n_J]
                u_k = worst_case_jammer(c_k, s; method=method, optimizer=optimizer, total_time=total_algorithm_time,
                             U_max=U_max,   # ← pass through
                             u_max=u_max)   # ← pass through)
                push!(new_scenarios, u_k)
            end
        end
        iter_time += t_sub

        # Add new worst-case scenarios
        append!(S, new_scenarios)

        # ---------------------------------------------------------------------
        # Master Problem: Update power allocation
        # ---------------------------------------------------------------------
        t_master = @elapsed p_opt, τ_current = solve_master_wireless(h, g, p_bar, gamma, sigma2, S; optimizer=optimizer, total_time=total_algorithm_time)
        iter_time += t_master
        total_algorithm_time += iter_time

        push!(tau_history, (ℓ, τ_current))
        p_current = p_opt

        # ---------------------------------------------------------------------
        # Convergence Check
        # ---------------------------------------------------------------------
        Δτ = ℓ > 1 ? abs(τ_current - τ_prev) : "N/A"

        if ℓ > 1 && isfinite(τ_current) && isfinite(τ_prev) && abs(τ_current - τ_prev) <= tol
            if verbose
                println("✅ Converged at iteration $ℓ: Δτ = $(abs(τ_current - τ_prev)) ($method | Seed $seed | m_UE=$m_UE)")
            end
            break
        end

        τ_prev = τ_current

        # ---------------------------------------------------------------------
        # Logging Progress
        # ---------------------------------------------------------------------
        if verbose && (ℓ == 1 || ℓ % 10 == 0)
            τ_str = isfinite(τ_current) ? round(τ_current, digits=6) : "Inf"
            delta_str = Δτ isa String ? Δτ : (isfinite(Δτ) ? round(Δτ, digits=6) : "Inf")
            println("Iteration $ℓ ($method | Seed $seed | m_UE=$m_UE): τ = $τ_str | Δτ = $delta_str | #Scenarios = $(length(S)) | Iter time = $(round(iter_time, digits=4))s")
        end
    end

    # -------------------------------------------------------------------------
    # Save results and summarize
    # -------------------------------------------------------------------------
    CSV.write("tau_wireless_$(method)_s$(s)_seed$(seed)_mUE$(m_UE)_nJ$(n_J)_nBS$(n_BS).csv",
              DataFrame(iteration=[t[1] for t in tau_history], tau=[t[2] for t in tau_history]))

    if verbose
        println("💾 Saved τ history: tau_wireless_$(method)_s$(s)_seed$(seed)_mUE$(m_UE)_nJ$(n_J)_nBS$(n_BS).csv")
        final_τ = isfinite(τ_prev) ? round(τ_prev, digits=6) : "Inf"
        #println("\n⏱️ TOTAL CUTTING-PLANE TIME ($method | Seed $seed | m_UE=$m_UE, n_J=$n_J, n_BS=$n_BS): $(round(total_algorithm_time, digits=4)) seconds")
        #println("📊 Final objective (τ): $final_τ")
    end

    return p_current, τ_prev, S, total_algorithm_time
end

println("✅ Cutting-plane wireless algorithm redefined successfully.")
