# =============================================================================                1
# 7. RUN EXPERIMENT FOR WIRELESS OPTIMIZATION (MULTI-SEED, MULTI-METHOD)
# =============================================================================               done
using CSV, DataFrames, PrettyTables, Statistics

# --- Wireless problem configuration ---
WIRELESS_CONFIGS = [
   (n_BS=5, n_J=20, m_UE=50)
   ,(n_BS=10, n_J=50, m_UE=200)
  ,(n_BS=20, n_J=100, m_UE=300)
]

SEEDS = [1
, 2, 3, 4, 5
]  

methods = [
     "heuristic",
     "relaxed", 
     "mip"]
sparsities = [
    1,2,3,5
    ]

all_results = []

println("\n" * "^"^60)
println("🚀 STARTING CUTTING-PLANE ALGORITHM FOR WIRELESS PROBLEM (ALL METHODS, MULTI-SEED)")
# println("📡 Problem configurations: $(WIRELESS_CONFIGS)")
println("^"^60)

for (config_idx, config) in enumerate(WIRELESS_CONFIGS)
    n_BS, n_J, m_UE = config.n_BS, config.n_J, config.m_UE

    println("\n" * "="^60)
    println("📏 CONFIGURATION $config_idx: n_BS = $n_BS | n_J = $n_J | m_UE = $m_UE")
    println("="^60)

    for seed in SEEDS
        println("\n" * "#" * "="^58 * "#")
        println("### 🌱 Starting Wireless Experiment for SEED = $seed | n_BS = $n_BS | n_J = $n_J | m_UE = $m_UE ###")
        println("#" * "="^58 * "#")

        # ---------------------------------------------------------------------
        # Data Loading from .mat
        # ---------------------------------------------------------------------
        println("✅ Loading wireless data from .mat (seed=$seed)...")
        h, g, p_bar, gamma, sigma2, U_MAX, U_MAX_PER_JAMMER = load_wireless_data(n_BS, n_J, m_UE; seed=seed)
        # Save loaded data (optional)
        CSV.write("h_nBS$(n_BS)_nJ$(n_J)_mUE$(m_UE)_seed$(seed).csv", DataFrame(h, :auto))
       # println("💾 Saved h-matrix for seed=$seed")
        # (Optional: Save g, sigma2, etc., if needed)

        # ---------------------------------------------------------------------
        # Nominal Problem (No Jamming)
        # ---------------------------------------------------------------------
        #println("🧠 Computing nominal (no-jamming) solution (seed=$seed)...")
        nominal_time = @elapsed p_nominal = solve_nominal_wireless(h, p_bar, gamma, sigma2)
        nominal_obj = sum(p_nominal)
        println("✅ Nominal power: $(round(nominal_obj, digits=6)) | Time: $(round(nominal_time, digits=4))s")

        # ---------------------------------------------------------------------
        # Cutting-Plane Experiments
        # ---------------------------------------------------------------------
        for method in methods
            for s in sparsities
                println("\n" * "-"^50)
                println("▶️ Solving for sparsity s = $s | Method = $method | Seed = $seed")
                println("-"^50)

                total_elapsed = @elapsed begin
                    p_opt, τ_opt, scenarios, algo_time = cutting_plane_wireless(
                        h, g, p_bar, gamma, sigma2, s;
                        method=method,
                        max_iter=1000,
                        tol=1e-5,
                        limit_time=1000.0,
                        verbose=true,
                        optimizer=Mosek.Optimizer,
                        p_init=p_nominal,
                        #p_init =  p_bar,
                        seed=seed,
                        m_UE=m_UE,
                        n_J=n_J,
                        n_BS=n_BS,
                        U_max=U_MAX,              # ← new keyword arg
                        u_max=U_MAX_PER_JAMMER    # ← new keyword arg
                    )
                end

                # Record results
                push!(all_results, (
                    seed = seed,
                    n_BS = n_BS,
                    n_J = n_J,
                    m_UE = m_UE,
                    method = method,
                    sparsity = s,
                    total_power = τ_opt,
                    scenarios = length(scenarios),
                    algo_time = algo_time,
                    nominal_obj = nominal_obj
                ))

                # Save solution
                df_p = DataFrame(index=1:length(p_opt), p=p_opt)
                CSV.write("p_opt_$(method)_s$(s)_seed$(seed)_mUE$(m_UE)_nJ$(n_J)_nBS$(n_BS).csv", df_p)
                #println("💾 Saved: p_opt_$(method)_s$(s)_seed$(seed)_mUE$(m_UE)_nJ$(n_J)_nBS$(n_BS).csv")

                println("🏁 $method (Seed $seed): τ = $(round(τ_opt, digits=6)) | #Scenarios = $(length(scenarios)) | CP Time = $(round(algo_time, digits=4))s")
            end
        end
    end
end

# =============================================================================
# 8. RESULTS ANALYSIS (FIXED TABLE PRINTING)
# =============================================================================
println("\n📊 FINAL AGGREGATE REPORT (Across all Seeds and Configurations)")

if isempty(all_results)
    println("❌ No results collected.")
else
    df_final = DataFrame(all_results)

    # Correct renaming: :total_power → :LB
    rename!(df_final, :sparsity => :s, :total_power => :LB, :scenarios => Symbol("#Scenarios"), :algo_time => Symbol("Time (s)"))
    sort!(df_final, [:n_BS, :n_J, :m_UE, :seed, :s, :method])

    # --- COMPUTE AND ADD SGAP COLUMN ---
    gdf = groupby(df_final, [:n_BS, :n_J, :m_UE, :s, :seed])
    transform!(gdf, :LB => (LB -> maximum(filter(isfinite, LB))) => :LB_best, renamecols=false)
    transform!(gdf, [:LB_best, :LB] => ((LB_best, LB) -> (LB_best .- LB) ./ (abs.(LB) .+ 1e-4) .* 100) => Symbol("SGap (%)"), renamecols=false)
    select!(df_final, Not(:LB_best))

    # --- Save Detailed Results ---
    for (n_BS, n_J, m_UE) in [(c.n_BS, c.n_J, c.m_UE) for c in WIRELESS_CONFIGS]
        df_final_subset = filter(row -> row.n_BS == n_BS && row.n_J == n_J && row.m_UE == m_UE, df_final)
        CSV.write("wireless_final_results_nBS$(n_BS)_nJ$(n_J)_mUE$(m_UE).csv", df_final_subset)
        println("💾 Saved detailed report: wireless_final_results_nBS$(n_BS)_nJ$(n_J)_mUE$(m_UE).csv")
    end

    # --- Aggregate Summary Statistics ---
    for (n_BS, n_J, m_UE) in [(c.n_BS, c.n_J, c.m_UE) for c in WIRELESS_CONFIGS]
        df_subset = filter(row -> row.n_BS == n_BS && row.n_J == n_J && row.m_UE == m_UE, df_final)
        df_summary = combine(
            groupby(df_subset, [:s, :method]),
            :LB => (x -> round(mean(filter(isfinite, x)), digits=6)) => Symbol("Avg LB"),
            :LB => (x -> round(std(filter(isfinite, x)), digits=6)) => Symbol("Std LB"),
            Symbol("Time (s)") => (x -> round(mean(x), digits=2)) => Symbol("Avg Time (s)"),
            Symbol("Time (s)") => (x -> round(std(x), digits=2)) => Symbol("Std Time (s)"),
            Symbol("SGap (%)") => (x -> round(mean(x), digits=2)) => Symbol("Avg SGap (%)"),
            Symbol("SGap (%)") => (x -> round(std(x), digits=2)) => Symbol("Std SGap (%)")
        )
        sort!(df_summary, [:s, :method])

        # --- Display summary table using println ---
        println("\n" * "="^100)
        println("Summary Statistics (Averaged Across Seeds) — Wireless: n_BS=$n_BS, n_J=$n_J, m_UE=$m_UE")
        println("="^100)
        
        # Print header
        @printf("%-6s %-12s %-12s %-10s %-14s %-14s %-14s %-14s\n",
                "s", "Method", "Avg LB", "Std LB", "Avg Time (s)", "Std Time (s)", "Avg SGap (%)", "Std SGap (%)")
        println("-"^100)
        
        # Print rows
        for row in eachrow(df_summary)
            @printf("%-6d %-12s %-12.6f %-10.6f %-14.2f %-14.2f %-14.2f %-14.2f\n",
                    row[:s],
                    row[:method],
                    row[Symbol("Avg LB")],
                    row[Symbol("Std LB")],
                    row[Symbol("Avg Time (s)")],
                    row[Symbol("Std Time (s)")],
                    row[Symbol("Avg SGap (%)")],
                    row[Symbol("Std SGap (%)")]
            )
        end
        println("="^100)

        # Save summary report
        CSV.write("wireless_summary_nBS$(n_BS)_nJ$(n_J)_mUE$(m_UE).csv", df_summary)
        println("💾 Saved summary report: wireless_summary_nBS$(n_BS)_nJ$(n_J)_mUE$(m_UE).csv")
    end

    println("\n🎉 Wireless experiments completed for all seeds and configurations.")
end

# time limit (limit_time) is checked once per iteration at the beginning of the main loop. Specifically, the check occurs before any subproblems or the master problem are solved for that iteration.